class LFUCache {
public:
    int capacity;
    int minFreq;
    int keyCount;
    unordered_map<int, pair<int, int>> keyToValAndFreq;
    unordered_map<int, list<int>> freqToList;
    unordered_map<int, list<int>::iterator> keyToListIter;

    LFUCache(int capacity) {
        this->capacity = capacity;
        this->minFreq = 0;
        this->keyCount = 0;
    }

    int get(int key) {
        if (keyToValAndFreq.find(key) == keyToValAndFreq.end()) {
            return -1;
        }
        int value = keyToValAndFreq[key].first;
        int freq = keyToValAndFreq[key].second;
        keyToValAndFreq[key].second++;
        freqToList[freq].erase(keyToListIter[key]);
        if (freqToList[freq].empty() && minFreq == freq) {
            minFreq++;
        }
        freqToList[freq + 1].push_back(key);
        keyToListIter[key] = --freqToList[freq + 1].end();
        return value;
    }

    void put(int key, int value) {
        if (capacity == 0) {
            return;
        }
        if (keyToValAndFreq.find(key) != keyToValAndFreq.end()) {
            keyToValAndFreq[key].first = value;
            get(key);
            return;
        }
        if (keyCount == capacity) {
            int keyToRemove = freqToList[minFreq].front();
            freqToList[minFreq].pop_front();
            keyToListIter.erase(keyToRemove);
            keyToValAndFreq.erase(keyToRemove);
            keyCount--;
        }
        keyToValAndFreq[key] = {value, 1};
        freqToList[1].push_back(key);
        keyToListIter[key] = --freqToList[1].end();
        minFreq = 1;
        keyCount++;
    }
};
